def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        factor = 1.0
        if ratio < 0.05:
            for a in range(1, 12):
                temp = np.exp(-ratio * a) * (a ** 3.0) * np.sin(a * ratio * np.pi)
                if a % 2 == 0:
                    temp *= 1.1
                else:
                    temp *= 0.95
                score += temp
            if (int(capacity) % 4 == 0) and ((int(item * 10) + i) % 5 == 0):
                score *= 0.75
            if score > 12:
                score /= (2.2 + ratio * 3)
        elif 0.05 <= ratio < 0.2:
            prod = 1.0
            for n in range(1, int(capacity) + 5):
                val = ratio + np.sin(n) / (n + 0.5)
                if val <= 0:
                    val = 1e-3
                prod *= val
                if prod > 1e8:
                    prod = np.log1p(prod)
                    break
            mod_val = int(prod * 7) % 400
            score += np.cbrt(ratio * mod_val + 2)
            if int(capacity * 3) % 8 == 0 and int(item * 5) % 4 == 0:
                score += 6.3
            else:
                score -= 1.2
            for x in range(1, 8):
                score += ((ratio * x**3) % 1) * np.log1p(x + 1)
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                pow_val = (ratio ** (m + 1.5)) * (m ** 3.1) / ((m + 1) ** 1.1)
                adjustment = np.cos(ratio * m * np.pi / 2)
                score += pow_val * adjustment
            remainder = capacity - item
            if remainder < 2:
                score += 18 + remainder * 0.75
                factor = 1.3
            else:
                score -= remainder * 1.1
                factor = 0.85
            if score < -8:
                score = abs(score) * 0.4 + 3
            if int(capacity * 2) % 9 == 0:
                score *= 1.5
            if score > 20:
                score /= 2.5
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0.0
            for p in range(1, 14):
                term = ((ratio - 0.5) ** p) * (p ** 2.2) * np.sin(p * ratio)
                penalty_base += term
                if abs(penalty_base) > 70:
                    penalty_base = np.sign(penalty_base) * np.log1p(abs(penalty_base))
                    break
            score = penalty_base * 16
            if capacity < item * 1.1:
                score += 22
            if (int(capacity * 7) % 9 == 0) or (int(item * 12) % 13 == 0):
                score -= 9
            if score < 0:
                score *= -1.7
                score += 7
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0.0
            diff = ratio - 0.8
            for q in range(1, 15):
                penalty_ext += ((diff) ** q) * (q ** 3.0) / (q + 0.8) * np.cos(diff * q)
            score = penalty_ext * 25
            if capacity < item * 1.5:
                score += 27
            if (int(capacity * 4) % 6 == 0) and (int(item * 15) % 5 == 0):
                score -= 11
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.0)
            if score < 0:
                score = abs(score) * 0.7
            if score > 1500:
                score = 1500
        else:
            super_penalty = 0.0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5) * np.cos(r * diff)
                if abs(term) > 15000:
                    term = np.sign(term) * np.sqrt(abs(term))
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 17) % 5 == 0) and (int(item * 23) % 7 == 0):
                score -= 15
            for w in range(2, 8):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 3.1
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score * factor
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 1
    return priorities
